insert into dvs_story_data values (1, 2, 8, 0, 5118061, 'フリーマーケットを訪れたジータが出会ったのは\\n城をこっそり抜け出していたペコリーヌだった。', 91002, 7, 10118, 'ペコリーヌとの出会い', '青空の下で謁見', 2834, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 2, 8, 0, 5118062, 'ジータたちがフリーマーケットを巡っていると\\n露店を出していたマホに声をかけられる。', 91002, 7, 10118, 'マホとの出会い', '未来の騎空団\\nマスコット？', 2835, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 2, 8, 0, 5118063, 'ジータが騎空団への依頼を確認していると、\\n高笑いをしながらアキノが現れる。', 91002, 7, 10118, 'アキノとの出会い', 'お嬢さまからの\\n緊急依頼', 2837, 40, 0, 'ランドソル市街地');
insert into dvs_story_data values (1, 2, 8, 0, 5118064, 'ジータたちは、フリーマーケット会場で\\n少し困った様子のジュンを見かける。', 91002, 18, 10118, 'ジュンとの出会い', '黄金色の悩みごと', 4108402, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 2, 8, 0, 5118065, 'フリーマーケットの隅で開かれる格闘大会──\\nそこにはカオリもいて……？', 91002, 18, 10118, 'カオリとの出会い', '白熱！\u3000格闘大会！', 4107402, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 2, 8, 0, 5118066, '太鼓祭を控えるオーエド町──\\nジータは、困った様子のニノンと出会う。', 91002, 16, 10118, 'ニノンとの出会い', '祭り太鼓はオーエドの華', 9000227, 40, 1, 'オーエド町');
insert into dvs_story_data values (1, 3, 8, 0, 5118067, 'ビカラはイベントに出演中のスズナを見かける。\\nしかし、スズナはどこか困っているようで……？', 91002, 19, 10118, 'スズナとの出会い', '人気者は遅れて\\nやってくる', 2101181, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 3, 8, 0, 5118068, 'ビカラたちが街を散策していると、通りかかった\\nナナカが興奮した様子で近づいてきて……？', 91002, 18, 10118, 'ナナカとの出会い', '巫女・ミーツ・魔法少女', 4109402, 40, 0, 'ランドソル市街地');
insert into dvs_story_data values (1, 3, 8, 0, 5118069, 'ネズ耳をなくしてしまい絶望するビカラ。同じ頃\\nキャルとコッコロは落とし物を拾っており……', 91002, 18, 10118, 'キャル＆コッコロとの出会い', 'ネズ耳は二度なくなる', 4305402, 40, 0, 'フリーマーケット会場');
insert into dvs_story_data values (1, 3, 8, 0, 5118070, '街外れでひと休みをしていたビカラたちは、\\nすっかりゴキゲンな様子のユカリと出会う。', 91002, 18, 10118, 'ユカリとの出会い', 'この出会いにカンパイ！', 4101402, 40, 0, 'ランドソル市街地');
insert into dvs_story_data values (1, 3, 8, 0, 5118071, 'ビカラは、人混みに怯えるアオイを心配し、\\n陽気に声をかけるも……', 91002, 18, 10118, 'アオイとの出会い', '陰陽アンサンブル', 4106402, 40, 0, 'ランドソル市街地');
insert into dvs_story_data values (1, 3, 8, 0, 5118072, 'ビカラがフリーマーケット会場を歩いていると\\n占いをしていたシノブに声をかけられる。', 91002, 7, 10118, 'シノブとの出会い', '運試し十番勝負！', 2836, 40, 1, 'フリーマーケット会場');
insert into dvs_story_data values (0, 1, 0, 10145115, 5118600, '0', 0, 0, 10118, 'オープニング', '彼女たちの新たな日常', 0, 0, 0, '0');
